// ---------------------------------------------------------------------------
// Brand mark
// ---------------------------------------------------------------------------
const LOGO_WHITE = "data:image/png;base64,";
const LOGO_BLACK = "data:image/png;base64,";

const ThemeContext = createContext(null);
function useTheme() {
  return useContext(ThemeContext);
}

function CoopLogo({ size = 40 }) {
  const { mode } = useTheme();
  return <img src={mode === "dark" ? LOGO_WHITE : LOGO_BLACK} alt="cOOps" style={{ height: size, width: "auto" }} className="select-none pointer-events-none" />;
}

function buildTokens(mode) {
  const dark = mode === "dark";
  return {
    mode,
    text: dark ? "text-white" : "text-black",
    sub: dark ? "text-white/50" : "text-black/55",
    sub2: dark ? "text-white/35" : "text-black/40",
    surface: dark ? "bg-white/[0.07]" : "bg-black/[0.045]",
    surfaceSoft: dark ? "bg-white/[0.035]" : "bg-black/[0.025]",
    surfaceActive: dark ? "bg-white/[0.12]" : "bg-black/[0.08]",
    shadow: dark ? "shadow-[0_12px_34px_-10px_rgba(0,0,0,0.65)]" : "shadow-[0_12px_34px_-14px_rgba(0,0,0,0.18)]",
    shadowSm: dark ? "shadow-[0_6px_18px_-8px_rgba(0,0,0,0.6)]" : "shadow-[0_6px_18px_-8px_rgba(0,0,0,0.14)]",
    navBg: dark ? "bg-black/75" : "bg-white/75",
    solidBg: dark ? "bg-[#0c0d0f]" : "bg-white",
    placeholder: dark ? "placeholder:text-white/30" : "placeholder:text-black/30",
    divide: dark ? "divide-white/[0.06]" : "divide-black/[0.06]",
    iconMuted: dark ? "text-white/65" : "text-black/60",
    iconFaint: dark ? "text-white/25" : "text-black/25",
    overlay: dark ? "bg-black/70" : "bg-black/25",
    press: "transition-all duration-150 active:scale-[0.94] hover:brightness-110",
    cardHover: "transition-all duration-200 hover:-translate-y-0.5",
  };
}

// ---------------------------------------------------------------------------
// Decorative background
// ---------------------------------------------------------------------------
function AppBackground() {
  const { mode } = useTheme();
  const dark = mode === "dark";
  return (
    <div className="fixed inset-0 -z-10 overflow-hidden" style={{ background: dark ? "#08090b" : "#f6f6f3" }}>
      <div className="absolute -top-32 -left-24 w-[420px] h-[420px] rounded-full blur-3xl" style={{ background: dark ? "radial-gradient(circle, rgba(16,185,129,0.22), transparent 70%)" : "radial-gradient(circle, rgba(16,185,129,0.18), transparent 70%)" }} />
      <div className="absolute top-1/3 -right-28 w-[380px] h-[380px] rounded-full blur-3xl" style={{ background: dark ? "radial-gradient(circle, rgba(139,92,246,0.16), transparent 70%)" : "radial-gradient(circle, rgba(139,92,246,0.12), transparent 70%)" }} />
      <div className="absolute bottom-0 left-1/4 w-[460px] h-[460px] rounded-full blur-3xl" style={{ background: "radial-gradient(circle, rgba(56,189,248,0.10), transparent 70%)" }} />
      <div
        className="absolute inset-0"
        style={{
          backgroundImage: dark
            ? "linear-gradient(rgba(255,255,255,0.035) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.035) 1px, transparent 1px)"
            : "linear-gradient(rgba(0,0,0,0.03) 1px, transparent 1px), linear-gradient(90deg, rgba(0,0,0,0.03) 1px, transparent 1px)",
          backgroundSize: "34px 34px",
          maskImage: "radial-gradient(ellipse 80% 60% at 50% 0%, black 40%, transparent 90%)",
          WebkitMaskImage: "radial-gradient(ellipse 80% 60% at 50% 0%, black 40%, transparent 90%)",
        }}
      />
    </div>
  );
}

