// ---------------------------------------------------------------------------
// Shared bits
// ---------------------------------------------------------------------------
function Card({ children, className = "", interactive = false }) {
  const t = useTheme();
  return <div className={`rounded-2xl ${t.surfaceSoft} ${t.shadow} backdrop-blur-sm ${interactive ? t.cardHover : ""} ${className}`}>{children}</div>;
}

function IconBtn({ children, onClick, className = "" }) {
  const t = useTheme();
  return (
    <button onClick={onClick} className={`w-10 h-10 rounded-full ${t.surface} ${t.shadowSm} ${t.press} flex items-center justify-center ${t.iconMuted} shrink-0 ${className}`}>
      {children}
    </button>
  );
}

function TopBar({ onOpenNotifications }) {
  const t = useTheme();
  return (
    <div className="flex items-center justify-between mb-6">
      <CoopLogo size={30} />
      <div className="flex items-center gap-2">
        <IconBtn onClick={t.toggle}>{t.mode === "dark" ? <Sun size={15} /> : <Moon size={15} />}</IconBtn>
        <IconBtn onClick={onOpenNotifications}>
          <Bell size={15} />
        </IconBtn>
      </div>
    </div>
  );
}

function ScreenHeader({ title, subtitle, onBack, right }) {
  const t = useTheme();
  return (
    <div className="flex items-center justify-between mb-6">
      <div className="flex items-center gap-2">
        {onBack && <IconBtn onClick={onBack} className="mr-1"><ChevronLeft size={16} /></IconBtn>}
        <div>
          <h1 className={`text-xl font-semibold tracking-tight font-display ${t.text}`}>{title}</h1>
          {subtitle && <p className={`text-sm mt-0.5 ${t.sub}`}>{subtitle}</p>}
        </div>
      </div>
      {right || (
        <IconBtn>
          <Bell size={15} />
        </IconBtn>
      )}
    </div>
  );
}

function Segmented({ options, value, onChange }) {
  const t = useTheme();
  return (
    <div className={`flex gap-1 p-1 rounded-full ${t.surfaceSoft} ${t.shadowSm} w-fit mb-4`}>
      {options.map((o) => (
        <button
          key={o.id}
          onClick={() => onChange(o.id)}
          className={`text-xs font-medium px-4 py-1.5 rounded-full ${t.press} ${value === o.id ? "bg-emerald-500 text-black" : t.sub}`}
        >
          {o.label}
        </button>
      ))}
    </div>
  );
}

function Sheet({ title, icon: TitleIcon, onClose, children }) {
  const t = useTheme();
  return (
    <div className="absolute inset-0 z-50 flex flex-col justify-end">
      <div className={`absolute inset-0 ${t.overlay} backdrop-blur-sm`} onClick={onClose} />
      <div className={`relative rounded-t-3xl ${t.solidBg} ${t.shadow} px-5 pt-4 pb-8 max-h-[88%] overflow-y-auto`}>
        <div className={`w-10 h-1 rounded-full mx-auto mb-5 ${t.mode === "dark" ? "bg-white/20" : "bg-black/15"}`} />
        <div className="flex items-center justify-between mb-5">
          <h2 className={`text-base font-semibold flex items-center gap-2 font-display ${t.text}`}>
            {TitleIcon && <TitleIcon size={16} />} {title}
          </h2>
          <IconBtn onClick={onClose}>
            <X size={14} />
          </IconBtn>
        </div>
        {children}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Plan card — with like + comment section
// ---------------------------------------------------------------------------
function PlanCard({ plan, joined, onToggleJoin, onOpenChat, liked, onToggleLike, comments, onAddComment, compact = false }) {
  const t = useTheme();
  const [showComments, setShowComments] = useState(false);
  const [draft, setDraft] = useState("");

  return (
    <Card interactive className="p-3.5">
      <div className="flex items-start gap-3">
        <div className={`relative w-16 h-16 rounded-xl shrink-0 bg-gradient-to-br ${plan.gradient} flex items-center justify-center`}>
          <plan.icon size={22} className={t.iconMuted} />
          {plan.visibility === "private" && (
            <span className={`absolute -top-1.5 -right-1.5 w-5 h-5 rounded-full ${t.solidBg} ${t.shadowSm} flex items-center justify-center`}>
              <Lock size={10} className={t.iconMuted} />
            </span>
          )}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-start justify-between gap-2">
            <p className={`text-sm font-semibold leading-snug pr-2 ${t.text}`}>{plan.title}</p>
            <button
              onClick={() => onToggleJoin(plan.id)}
              className={`shrink-0 text-xs font-semibold px-4 py-1.5 rounded-full ${t.press} ${joined ? `${t.surfaceActive} text-emerald-400` : "bg-emerald-500 text-black"}`}
            >
              {joined ? "Joined" : "Join"}
            </button>
          </div>
          <p className="text-[11px] mt-1.5">
            <span className="text-emerald-400 font-medium">{plan.members}</span> <span className={t.sub2}>members joined</span>
          </p>
          {!compact && (
            <div className="flex items-center justify-between mt-2 text-[11px]">
              <span className={t.sub2}>
                Avg Goal <span className={`font-medium ${t.text}`}>{plan.avgGoal}</span>
              </span>
              <span className={t.sub2}>
                Total Saved <span className={`font-medium ${t.text}`}>{plan.totalSaved}</span>
              </span>
            </div>
          )}
        </div>
      </div>

      <div className={`flex items-center gap-1 mt-3 pt-3 ${t.mode === "dark" ? "border-t border-white/[0.06]" : "border-t border-black/[0.06]"}`}>
        <button onClick={() => onToggleLike(plan.id)} className={`flex-1 flex items-center justify-center gap-1.5 text-xs py-1.5 rounded-xl ${t.press} ${liked ? "text-rose-400" : t.sub}`}>
          <Heart size={13} fill={liked ? "currentColor" : "none"} /> {plan.likes + (liked ? 1 : 0)}
        </button>
        <button onClick={() => setShowComments((v) => !v)} className={`flex-1 flex items-center justify-center gap-1.5 text-xs py-1.5 rounded-xl ${t.press} ${t.sub}`}>
          <MessageSquare size={13} /> {comments.length}
        </button>
        <button onClick={() => onOpenChat(plan)} className={`flex-1 flex items-center justify-center gap-1.5 text-xs py-1.5 rounded-xl ${t.press} ${t.sub}`}>
          <MessageCircle size={13} /> Chat
        </button>
      </div>

      {showComments && (
        <div className="mt-2 flex flex-col gap-2">
          {comments.slice(-3).map((c, i) => (
            <div key={i} className={`text-xs ${t.sub} ${t.surfaceSoft} rounded-xl px-3 py-2`}>
              <span className={`font-medium ${t.text}`}>{c.author}</span> {c.text}
            </div>
          ))}
          <div className={`flex items-center gap-2 rounded-full px-3 py-1.5 ${t.surfaceSoft}`}>
            <input
              value={draft}
              onChange={(e) => setDraft(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter" && draft.trim()) {
                  onAddComment(plan.id, draft.trim());
                  setDraft("");
                }
              }}
              placeholder="Add a comment..."
              className={`flex-1 bg-transparent text-xs outline-none ${t.text} ${t.placeholder}`}
            />
          </div>
        </div>
      )}
    </Card>
  );
}

// ---------------------------------------------------------------------------
// Community feed — single scrollable Twitter-style frame
// ---------------------------------------------------------------------------
function CommunityFeed({ posts, onAddPost, likedPosts, onToggleLike, heightClass = "max-h-[440px]" }) {
  const t = useTheme();
  const [draft, setDraft] = useState("");

  return (
    <Card className="overflow-hidden">
      <div className="p-4">
        <textarea
          value={draft}
          onChange={(e) => setDraft(e.target.value)}
          placeholder="What are you saving for today?"
          rows={2}
          className={`w-full bg-transparent text-sm outline-none resize-none ${t.text} ${t.placeholder}`}
        />
        <div className="flex justify-end">
          <button
            onClick={() => {
              if (!draft.trim()) return;
              onAddPost(draft.trim());
              setDraft("");
            }}
            className={`text-xs font-semibold bg-emerald-500 text-black px-4 py-1.5 rounded-full ${t.press}`}
          >
            Post
          </button>
        </div>
      </div>

      <div className={`${heightClass} overflow-y-auto divide-y ${t.divide}`}>
        {posts.map((post) => (
          <div key={post.id} className={`p-4 ${t.press} hover:brightness-100 ${t.mode === "dark" ? "hover:bg-white/[0.03]" : "hover:bg-black/[0.02]"}`}>
            <div className="flex items-start gap-2.5">
              <span className={`w-9 h-9 rounded-full ${t.surface} flex items-center justify-center shrink-0`}>
                <User size={14} className={t.iconMuted} />
              </span>
              <div className="flex-1 min-w-0">
                <p className={`text-sm ${t.text}`}>
                  <span className="font-semibold">{post.name}</span> <span className={t.sub2}>{post.handle} · {post.time}</span>
                </p>
                <p className={`text-sm leading-snug mt-0.5 mb-2.5 ${t.text} opacity-90`}>{post.text}</p>
                <div className={`flex items-center gap-6 ${t.sub2}`}>
                  <button className="flex items-center gap-1.5 text-xs">
                    <MessageSquare size={14} /> {post.comments}
                  </button>
                  <button className="flex items-center gap-1.5 text-xs">
                    <Repeat2 size={14} /> {post.reposts}
                  </button>
                  <button onClick={() => onToggleLike(post.id)} className={`flex items-center gap-1.5 text-xs ${likedPosts.has(post.id) ? "text-rose-400" : ""}`}>
                    <Heart size={14} fill={likedPosts.has(post.id) ? "currentColor" : "none"} />
                    {post.likes + (likedPosts.has(post.id) ? 1 : 0)}
                  </button>
                  <button className="flex items-center gap-1.5 text-xs">
                    <Share2 size={14} />
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </Card>
  );
}

