// ---------------------------------------------------------------------------
// Create Plan sheet
// ---------------------------------------------------------------------------
function CreatePlanSheet({ onClose, onCreate }) {
  const t = useTheme();
  const [name, setName] = useState("");
  const [category, setCategory] = useState("hot");
  const [visibility, setVisibility] = useState("public");
  const [target, setTarget] = useState("");
  const [cohorts, setCohorts] = useState("");

  const submit = () => {
    if (!name.trim()) return;
    const catMeta = CATEGORIES.find((c) => c.id === category);
    onCreate({
      id: "custom-" + Date.now(),
      title: name.trim(),
      icon: catMeta ? catMeta.icon : Sparkles,
      category,
      members: "1",
      avgGoal: target ? `${target}` : "—",
      totalSaved: "0",
      gradient: "from-emerald-500/25 to-teal-600/10",
      likes: 0,
      comments: [],
      visibility,
      cohorts: cohorts.trim(),
    });
    onClose();
  };

  return (
    <Sheet title="Create a plan" icon={Plus} onClose={onClose}>
      <div className="flex flex-col gap-4">
        <div>
          <label className={`text-xs mb-1.5 block ${t.sub2}`}>Plan name</label>
          <input
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="e.g. Wedding Plan"
            className={`w-full rounded-xl px-4 py-3 text-sm outline-none ${t.surfaceSoft} ${t.text} ${t.placeholder}`}
          />
        </div>

        <div>
          <label className={`text-xs mb-1.5 block ${t.sub2}`}>Category</label>
          <div className="flex gap-2 overflow-x-auto pb-1">
            {CATEGORIES.map((c) => (
              <button
                key={c.id}
                onClick={() => setCategory(c.id)}
                className={`shrink-0 flex items-center gap-1.5 text-xs font-medium px-3.5 py-2 rounded-full ${t.press} ${category === c.id ? "bg-emerald-500 text-black" : `${t.surfaceSoft} ${t.sub}`}`}
              >
                <c.icon size={13} /> {c.label}
              </button>
            ))}
          </div>
        </div>

        <div>
          <label className={`text-xs mb-1.5 block ${t.sub2}`}>Visibility</label>
          <div className={`flex gap-1 p-1 rounded-full ${t.surfaceSoft} w-fit`}>
            {[
              { id: "public", label: "Public", icon: Globe },
              { id: "private", label: "Private", icon: Lock },
            ].map((v) => (
              <button
                key={v.id}
                onClick={() => setVisibility(v.id)}
                className={`flex items-center gap-1.5 text-xs font-medium px-4 py-1.5 rounded-full ${t.press} ${visibility === v.id ? "bg-emerald-500 text-black" : t.sub}`}
              >
                <v.icon size={12} /> {v.label}
              </button>
            ))}
          </div>
          {visibility === "private" && <p className={`text-[11px] mt-1.5 ${t.sub2}`}>Only people you invite can see or join this plan.</p>}
        </div>

        <div>
          <label className={`text-xs mb-1.5 block ${t.sub2}`}>Target amount ($)</label>
          <input
            value={target}
            onChange={(e) => setTarget(e.target.value.replace(/[^0-9]/g, ""))}
            placeholder="5000"
            inputMode="numeric"
            className={`w-full rounded-xl px-4 py-3 text-sm outline-none ${t.surfaceSoft} ${t.text} ${t.placeholder}`}
          />
        </div>

        <div>
          <label className={`text-xs mb-1.5 block ${t.sub2}`}>Invite cohorts (names or emails)</label>
          <input
            value={cohorts}
            onChange={(e) => setCohorts(e.target.value)}
            placeholder="e.g. Ada, Tunde, Chidi"
            className={`w-full rounded-xl px-4 py-3 text-sm outline-none ${t.surfaceSoft} ${t.text} ${t.placeholder}`}
          />
        </div>

        <button onClick={submit} className={`w-full rounded-2xl bg-emerald-500 text-black py-3.5 text-sm font-semibold ${t.press}`}>
          Create plan
        </button>
      </div>
    </Sheet>
  );
}

// ---------------------------------------------------------------------------
// Market screen
// ---------------------------------------------------------------------------
function MarketScreen({ plans, joined, onToggleJoin, onOpenChat, onClose, planLikes, onTogglePlanLike, planComments, onAddPlanComment, onCreatePlan }) {
  const t = useTheme();
  const [category, setCategory] = useState("hot");
  const [showMine, setShowMine] = useState(false);
  const [showCreate, setShowCreate] = useState(false);

  const visiblePlans = showMine ? plans.filter((p) => joined.has(p.id)) : plans.filter((p) => p.category === category && p.visibility !== "private");

  return (
    <div>
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <IconBtn onClick={onClose}>
            <ChevronLeft size={16} />
          </IconBtn>
          <h1 className={`text-lg font-semibold ml-1 font-display ${t.text}`}>Popular Targets</h1>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setShowMine((v) => !v)} className={`text-xs ${t.press} ${showMine ? "text-emerald-400" : t.sub2}`}>
            My Targets
          </button>
          <button onClick={() => setShowCreate(true)} className={`flex items-center gap-1 text-xs font-semibold bg-emerald-500 text-black px-3 py-1.5 rounded-full ${t.press}`}>
            <Plus size={13} /> Create
          </button>
        </div>
      </div>

      {!showMine && (
        <div className="flex gap-2 mb-4 overflow-x-auto pb-1 -mx-5 px-5">
          {CATEGORIES.map((c) => (
            <button
              key={c.id}
              onClick={() => setCategory(c.id)}
              className={`shrink-0 flex items-center gap-1.5 text-xs font-medium px-3.5 py-2 rounded-full ${t.press} ${category === c.id ? "bg-emerald-500 text-black" : `${t.surfaceSoft} ${t.sub}`}`}
            >
              <c.icon size={13} /> {c.label}
            </button>
          ))}
        </div>
      )}

      <div className="flex flex-col gap-2.5 mb-6">
        {visiblePlans.length === 0 && <p className={`text-sm text-center py-10 ${t.sub2}`}>No targets here yet.</p>}
        {visiblePlans.map((p) => (
          <PlanCard
            key={p.id}
            plan={p}
            joined={joined.has(p.id)}
            onToggleJoin={onToggleJoin}
            onOpenChat={onOpenChat}
            liked={planLikes.has(p.id)}
            onToggleLike={onTogglePlanLike}
            comments={planComments[p.id] || []}
            onAddComment={onAddPlanComment}
          />
        ))}
      </div>

      {showCreate && <CreatePlanSheet onClose={() => setShowCreate(false)} onCreate={onCreatePlan} />}
    </div>
  );
}

