// ---------------------------------------------------------------------------
// Group chat — WhatsApp-style
// ---------------------------------------------------------------------------
function GroupChatScreen({ plan, onBack }) {
  const t = useTheme();
  const [messages, setMessages] = useState(() => chatSeed(plan.title));
  const [draft, setDraft] = useState("");

  const send = () => {
    if (!draft.trim()) return;
    setMessages((m) => [...m, { from: "me", text: draft.trim(), time: "now" }]);
    setDraft("");
  };

  const wallpaper = t.mode === "dark" ? "#0b141a" : "#e9e3d8";
  const headerBg = t.mode === "dark" ? "#1f2c34" : "#f0f2f5";
  const outgoingBg = t.mode === "dark" ? "#005c4b" : "#d9fdd3";
  const incomingBg = t.mode === "dark" ? "#202c33" : "#ffffff";
  const bubbleText = t.mode === "dark" ? "#e9edef" : "#111b21";

  return (
    <div className={`rounded-3xl overflow-hidden ${t.shadow} flex flex-col`} style={{ height: "74vh" }}>
      <div style={{ background: headerBg }} className="flex items-center gap-3 px-3 py-3">
        <button onClick={onBack} className="w-8 h-8 rounded-full flex items-center justify-center" style={{ color: bubbleText }}>
          <ChevronLeft size={18} />
        </button>
        <span className={`w-9 h-9 rounded-full bg-gradient-to-br ${plan.gradient} flex items-center justify-center`}>
          <plan.icon size={16} style={{ color: bubbleText }} />
        </span>
        <div className="flex-1 min-w-0">
          <p className="text-sm font-medium truncate" style={{ color: bubbleText }}>{plan.title}</p>
          <p className="text-[11px] opacity-60" style={{ color: bubbleText }}>online</p>
        </div>
        <Video size={17} style={{ color: bubbleText, opacity: 0.7 }} />
        <Phone size={16} style={{ color: bubbleText, opacity: 0.7 }} />
        <MoreVertical size={17} style={{ color: bubbleText, opacity: 0.7 }} />
      </div>

      <div style={{ background: wallpaper }} className="flex-1 overflow-y-auto px-3 py-4 flex flex-col gap-1.5">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.from === "me" ? "justify-end" : "justify-start"}`}>
            <div
              className={`max-w-[78%] px-3 py-2 text-sm shadow-sm ${m.from === "me" ? "rounded-2xl rounded-br-sm" : "rounded-2xl rounded-bl-sm"}`}
              style={{ background: m.from === "me" ? outgoingBg : incomingBg, color: bubbleText }}
            >
              {m.author && <p className="text-[11px] font-semibold mb-0.5 text-emerald-500">{m.author}</p>}
              <p>{m.text}</p>
              {m.time && <p className="text-[10px] opacity-50 text-right mt-0.5">{m.time}</p>}
            </div>
          </div>
        ))}
      </div>

      <div style={{ background: headerBg }} className="flex items-center gap-2 px-3 py-2.5">
        <Smile size={19} style={{ color: bubbleText, opacity: 0.7 }} />
        <Paperclip size={18} style={{ color: bubbleText, opacity: 0.7 }} />
        <input
          value={draft}
          onChange={(e) => setDraft(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && send()}
          placeholder="Message"
          className="flex-1 rounded-full px-4 py-2 text-sm outline-none"
          style={{ background: t.mode === "dark" ? "#2a3942" : "#ffffff", color: bubbleText }}
        />
        <button onClick={send} className={`w-9 h-9 rounded-full flex items-center justify-center ${t.press}`} style={{ background: "#00a884" }}>
          {draft ? <Send size={15} color="#0b141a" /> : <Mic size={15} color="#0b141a" />}
        </button>
      </div>
    </div>
  );
}

